def median(nums):
    if not nums:
        return None

    sorted_nums = sorted(nums)
    n = len(sorted_nums)

    if n % 2 == 1:
        return float(sorted_nums[n // 2])
    else:
        middle1 = sorted_nums[n // 2 - 1]
        middle2 = sorted_nums[n // 2]
        return (middle1 + middle2) / 2.0
